// Polling Green API — receiveNotification
const notif = $input.first().json;

// Pas de notification en attente → stop silencieusement
if (!notif || !notif.receiptId) return [];

const body = notif.body || {};
const typeWebhook = body.typeWebhook || '';
const isIncoming = typeWebhook === 'incomingMessageReceived';
const isOutgoing = typeWebhook === 'outgoingMessageReceived';

// Ignorer les webhooks non-texte (status, device, etc.)
if (!isIncoming && !isOutgoing) return [];

const msgData    = body.messageData || {};
const textMsg    = msgData.textMessageData || msgData.extendedTextMessageData || {};
const senderData = body.senderData || {};

const message = (textMsg.textMessage || textMsg.text || '').trim();
if (!message) return [];

const chatId = senderData.chatId || senderData.sender || '';
const rawPhone = isIncoming ? (senderData.sender || '') : (senderData.chatId || '');
const phone = rawPhone.replace('@c.us','').replace(/\D/g,'');
if (!phone) return [];

// Anti-boucle : ignorer les réponses du bot
const BOT_PREFIXES = ['📊','✅','❌','🤖','📅','⚠️','🏥','🗓️','👥','🎯','⏰','⏱️','⚖️','🏆'];
if (isOutgoing && BOT_PREFIXES.some(p => message.startsWith(p))) return [];

return [{ json: {
  phone_number: '+' + phone,
  chat_id: chatId,
  message_text: message,
  message_id: msgData.idMessage || body.idMessage || '',
  timestamp: body.timestamp || Date.now(),
  receiptId: notif.receiptId
}}];

const msgData = $('Extraire Message').first().json;
const dbRows = $input.all();
const user = dbRows.length > 0 && dbRows[0].json?.phone_number ? dbRows[0].json : null;

if (!user) {
  return [{ json: { ...msgData, authorized: false, user_role: null, allowed_scope_type: null, allowed_scope_value: null } }];
}
return [{ json: {
  ...msgData,
  authorized: true,
  user_role: user.role,
  user_name: user.full_name,
  allowed_scope_type: user.allowed_scope_type,
  allowed_scope_value: user.allowed_scope_value,
  language_pref: user.language_pref || 'fr'
}}];

// ============================================================
// NLP AVANCÉ — Détection langue + intent + métrique + scope
// ⚠️  ML = Maladie | MD = Mise en demeure | SÉPARÉS
// ============================================================
const data = $input.first().json;
const rawText = data.message_text || '';
const t = rawText.toLowerCase().trim();

const ALLOWED_METRICS = new Set([
  'actif','present','nb_abs','p','np','sq','ac','rv',
  'ml','md','maladie','mise_en_demeure',
  'abs_p_rate','abs_np_rate','total_abs','taux_presence',
  'heures_presence','retard','heures_sup','soll','ist','delta'
]);

function detectLang(t) {
  if (/[\u0600-\u06FF]/.test(t)) return 'ar';
  const tn = ['a3tini','9adech','chnowa','chkoun','mta3','lyoum','fi ','barsha','waqteh','chbih','akther','fih','bech','3andek','ma3ndich'];
  if (tn.some(w => t.includes(w))) return 'tn';
  return 'fr';
}

function detectDate(t) {
  const iso = t.match(/(\d{4}-\d{2}-\d{2})/);
  if (iso) return { mode: 'specific', date: iso[0] };
  const dmy = t.match(/(\d{1,2})[/\-](\d{1,2})[/\-](\d{4})/);
  if (dmy) return { mode: 'specific', date: `${dmy[3]}-${dmy[2].padStart(2,'0')}-${dmy[1].padStart(2,'0')}` };
  if (/aujourd|lyoum|اليوم|today/.test(t)) return { mode: 'today', date: null };
  if (/hier|امس|yesterday/.test(t)) return { mode: 'yesterday', date: null };
  return { mode: 'latest', date: null };
}

function detectMetric(t) {
  if (/taux.*np|pourcentage.*np|%.*np|نسبة.*np|chnowa.*np|taux abs np|abs np rate/.test(t)) return 'abs_np_rate';
  if (/taux.*\bp\b|pourcentage.*\bp\b|%.*\bp\b|taux abs p|abs p rate/.test(t)) return 'abs_p_rate';
  if (/taux.*pré|taux.*presence|نسبة.*حضور|taux presence/.test(t)) return 'taux_presence';
  if (/\bnp\b|absence np|abs np|non plan|غياب.*غير|ghiyeb non/.test(t)) return 'np';
  if (/\bp\b|absence planif|abs p|غياب.*مخطط/.test(t) && !/np/.test(t)) return 'p';
  if (/\bsq\b|sans questionnaire|sans quest/.test(t)) return 'sq';
  if (/\bac\b|absence continue|abs continue/.test(t)) return 'ac';
  if (/\brv\b|rendez.vous|رnd/.test(t)) return 'rv';
  if (/\bml\b|maladie(?! légale.*md)|maladies(?! légale.*md)|مرض|maradh|nombre.*malad|malad/.test(t) && !/mise en demeure|\bmd\b/.test(t)) return 'maladie';
  if (/\bmd\b|mise en demeure/.test(t)) return 'mise_en_demeure';
  if (/\bdelta\b|soll.*ist|ist.*soll|écart/.test(t)) return 'delta';
  if (/\bsoll\b|planifié h/.test(t) && !/ist/.test(t)) return 'soll';
  if (/\bist\b|heures réelles/.test(t) && !/soll/.test(t)) return 'ist';
  if (/h.*sup|heures sup|hsup|heures supplémentaires/.test(t)) return 'heures_sup';
  if (/retard|تأخر/.test(t)) return 'retard';
  if (/actif|effectif|workforce/.test(t) && !/total|absence/.test(t)) return 'actif';
  if (/présent|present|حاضر/.test(t) && !/taux/.test(t)) return 'present';
  if (/résumé|resume|ملخص|tous.*indicateurs|all.*indicator|chiffres/.test(t)) return 'summary';
  if (/total.*abs|nombre.*abs|combien.*abs|9adech.*abs|قداش.*غياب/.test(t)) return 'total_abs';
  return 'total_abs';
}

function detectScope(t, userRole, scopeType, scopeVal) {
  const gMatch = t.match(/\b(g[-.]?\d{3,4}|g\s\d{3,4})\b/i);
  if (gMatch) return { type: 'group_name', value: gMatch[0].replace(/[\s.]/g,'-').toUpperCase() };
  const perims = ['pgtf','wpa','shelf modulaire','basis','muster','logistique','logistics','quality','maintenance'];
  for (const p of perims) if (t.includes(p)) return { type: 'perimeter', value: p.toUpperCase() };
  const procs = ['assembly','assemblage','montage','test','paint','peinture','body','karosserie','trim','chassis'];
  for (const p of procs) if (t.includes(p)) return { type: 'process', value: p.charAt(0).toUpperCase()+p.slice(1) };
  const cMatch = t.match(/\b(circuit\s*)?(c\d{1,2})\b/i);
  if (cMatch) return { type: 'circuit', value: cMatch[cMatch.length-1].toUpperCase() };
  const aMatch = t.match(/area\s+([\w-]+)|zone\s+([\w-]+)/);
  if (aMatch) return { type: 'area', value: (aMatch[1]||aMatch[2]).toUpperCase() };
  if (/bmw u11|plant|مصنع|الكل|tout le plant/.test(t)) return { type: 'plant', value: 'BMW U11' };
  if (userRole === 'supervisor' && scopeType && scopeVal) return { type: scopeType, value: scopeVal };
  return { type: 'plant', value: 'BMW U11' };
}

function detectIntent(t, metric) {
  if (metric === 'summary') return 'get_summary';
  if (/compare|vs\b|versus|بالمقارنة|compare.*entre/.test(t)) return 'compare';
  if (/plus.*abs|akther.*fih|أكثر.*غياب|le plus|top|classement/.test(t)) return 'top';
  return 'get_metric';
}

const lang = detectLang(t);
const dateInfo = detectDate(t);
const metric = detectMetric(t);
const scope = detectScope(t, data.user_role, data.allowed_scope_type, data.allowed_scope_value);
const intent = detectIntent(t, metric);
const safeMetric = (metric === 'summary') ? 'summary' : (ALLOWED_METRICS.has(metric) ? metric : 'total_abs');

return [{ json: {
  ...data,
  nlp: {
    language: lang, intent,
    metric: safeMetric, metric_raw: metric,
    scope_type: scope.type, scope_value: scope.value,
    date_mode: dateInfo.mode, date: dateInfo.date,
    raw_text: rawText
  }
}}];

// ============================================================
// CONSTRUCTION REQUÊTE SQL SÉCURISÉE
// ⚠️  ML = Maladie | MD = Mise en demeure | SÉPARÉS
// ============================================================
const data = $input.first().json;
const nlp = data.nlp;
const userRole = data.user_role;
const userScopeType = data.allowed_scope_type;
const userScopeValue = data.allowed_scope_value;

function resolveDate(mode, dateVal) {
  if (mode === 'specific' && dateVal) return `'${dateVal}'::date`;
  if (mode === 'today') return 'CURRENT_DATE';
  if (mode === 'yesterday') return 'CURRENT_DATE - INTERVAL \'1 day\'';
  return '(SELECT MAX(report_date) FROM daily_hr_report)';
}
const dateExpr = resolveDate(nlp.date_mode, nlp.date);

function getScopeFilter(scopeType, scopeValue, userRole, userScopeType, userScopeValue) {
  let type = scopeType; let val = scopeValue;
  if (userRole === 'supervisor' && userScopeType && userScopeValue) {
    if (type === 'plant' || type === 'all') { type = userScopeType; val = userScopeValue; }
    else if (type !== userScopeType || val.toUpperCase() !== userScopeValue.toUpperCase()) {
      return { filter: `1=0`, scopeLabel: 'Non autorisé' };
    }
  }
  const colMap = { 'group_name':'group_name','perimeter':'perimeter','process':'process','circuit':'circuit','area':'area','plant':'plant' };
  const col = colMap[type] || 'plant';
  if (type === 'plant') return { filter: `plant ILIKE '${val.replace(/'/g,"''")}' `, scopeLabel: val };
  return { filter: `${col} ILIKE '%${val.replace(/'/g,"''")}%'`, scopeLabel: val };
}

const scopeCols = { 'plant':'plant','perimeter':'perimeter','process':'process','circuit':'circuit','group_name':'group_name','area':'area' };
const groupCol = scopeCols[nlp.scope_type] || 'plant';
const { filter, scopeLabel } = getScopeFilter(nlp.scope_type, nlp.scope_value, userRole, userScopeType, userScopeValue);

let query = '';

if (nlp.intent === 'get_summary') {
  query = `SELECT report_date, ${groupCol} AS scope_label, SUM(actif) AS actif, SUM(present) AS present, SUM(nb_abs) AS nb_abs, SUM(p) AS p, SUM(np) AS np, SUM(sq) AS sq, SUM(ac) AS ac, SUM(rv) AS rv, SUM(ml) AS maladie, SUM(md) AS mise_en_demeure, SUM(total_abs) AS total_abs, ROUND(SUM(np)/NULLIF(SUM(actif),0)*100,2) AS abs_np_rate, ROUND(SUM(p)/NULLIF(SUM(actif),0)*100,2) AS abs_p_rate, ROUND(SUM(present)/NULLIF(SUM(actif),0)*100,2) AS taux_presence, SUM(retard) AS retard, SUM(heures_sup) AS heures_sup, SUM(soll) AS soll, SUM(ist) AS ist, ROUND(SUM(ist)-SUM(soll),2) AS delta FROM daily_hr_report WHERE report_date = ${dateExpr} AND ${filter} GROUP BY report_date, ${groupCol};`;
} else if (nlp.intent === 'top') {
  const metric = nlp.metric === 'maladie' ? 'ml' : nlp.metric === 'mise_en_demeure' ? 'md' : nlp.metric;
  const safeM = /^[a-z_]+$/.test(metric) ? metric : 'np';
  query = `SELECT report_date, ${groupCol} AS scope_label, SUM(${safeM}) AS value, SUM(actif) AS actif FROM daily_hr_report WHERE report_date = ${dateExpr} AND ${filter} GROUP BY report_date, ${groupCol} ORDER BY value DESC NULLS LAST LIMIT 5;`;
} else {
  const metricColMap = {
    'actif': 'SUM(actif) AS actif',
    'present': 'SUM(present) AS present',
    'nb_abs': 'SUM(nb_abs) AS nb_abs',
    'p': 'SUM(p) AS p, SUM(actif) AS actif, ROUND(SUM(p)/NULLIF(SUM(actif),0)*100,2) AS abs_p_rate',
    'np': 'SUM(np) AS np, SUM(actif) AS actif, ROUND(SUM(np)/NULLIF(SUM(actif),0)*100,2) AS abs_np_rate',
    'sq': 'SUM(sq) AS sq',
    'ac': 'SUM(ac) AS ac',
    'rv': 'SUM(rv) AS rv',
    'ml': 'SUM(ml) AS maladie',
    'maladie': 'SUM(ml) AS maladie',
    'md': 'SUM(md) AS mise_en_demeure',
    'mise_en_demeure': 'SUM(md) AS mise_en_demeure',
    'abs_np_rate': 'SUM(np) AS np, SUM(actif) AS actif, ROUND(SUM(np)/NULLIF(SUM(actif),0)*100,2) AS abs_np_rate',
    'abs_p_rate': 'SUM(p) AS p, SUM(actif) AS actif, ROUND(SUM(p)/NULLIF(SUM(actif),0)*100,2) AS abs_p_rate',
    'total_abs': 'SUM(total_abs) AS total_abs, SUM(p) AS p, SUM(np) AS np',
    'taux_presence': 'SUM(present) AS present, SUM(actif) AS actif, ROUND(SUM(present)/NULLIF(SUM(actif),0)*100,2) AS taux_presence',
    'heures_presence': 'SUM(heures_presence) AS heures_presence',
    'retard': 'SUM(retard) AS retard',
    'heures_sup': 'SUM(heures_sup) AS heures_sup',
    'soll': 'SUM(soll) AS soll, SUM(ist) AS ist, ROUND(SUM(ist)-SUM(soll),2) AS delta',
    'ist': 'SUM(ist) AS ist, SUM(soll) AS soll, ROUND(SUM(ist)-SUM(soll),2) AS delta',
    'delta': 'SUM(soll) AS soll, SUM(ist) AS ist, ROUND(SUM(ist)-SUM(soll),2) AS delta'
  };
  const selectExpr = metricColMap[nlp.metric] || 'SUM(total_abs) AS total_abs';
  query = `SELECT report_date, ${groupCol} AS scope_label, ${selectExpr} FROM daily_hr_report WHERE report_date = ${dateExpr} AND ${filter} GROUP BY report_date, ${groupCol};`;
}

return [{ json: { ...data, sql_query: query.trim(), scope_label: scopeLabel, date_expr: dateExpr } }];

// ============================================================
// FORMATEUR RÉPONSE MULTILINGUE
// ⚠️  ML = Maladie | MD = Mise en demeure | SÉPARÉS
// ============================================================
const nlpData = $('NLP — Analyse Question').first().json;
const nlp = nlpData.nlp;
const sqlData = $('Construire SQL').first().json;
const rows = $input.all().map(i => i.json).filter(r => r && r.scope_label);
const lang = nlp.language;
const metric = nlp.metric;
const scope = sqlData.scope_label || nlp.scope_value || 'BMW U11';

function fmt(v, dec=1) { if(v===null||v===undefined)return'N/D'; return Number(v).toFixed(dec); }
function fmtDate(d) {
  if (!d) return 'N/D';
  try { return new Date(d).toLocaleDateString('fr-TN',{day:'2-digit',month:'2-digit',year:'numeric'}); }
  catch(e) { return d; }
}

if (!rows || rows.length === 0) {
  const noData = {
    fr: `⚠️ Aucune donnée disponible pour *${scope}*.

Vérifiez que le rapport a été importé pour cette date.`,
    ar: `⚠️ لا توجد بيانات متاحة لـ *${scope}*.`,
    tn: `⚠️ Makatech data disponible pour *${scope}*.`
  };
  return [{ json: {
    response_text: noData[lang] || noData.fr,
    chat_id: nlpData.chat_id,
    receiptId: nlpData.receiptId
  }}];
}

const agg = rows.reduce((a,r) => {
  ['actif','present','nb_abs','p','np','sq','ac','rv','ml','md','maladie','mise_en_demeure','total_abs','heures_presence','retard','heures_sup','soll','ist'].forEach(k => {
    a[k] = (a[k]||0) + (parseFloat(r[k])||0);
  });
  a.report_date = r.report_date;
  a.scope_label = r.scope_label;
  return a;
}, {});

agg.abs_np_rate   = agg.actif ? Math.round(agg.np/agg.actif*10000)/100 : (rows[0]?.abs_np_rate||0);
agg.abs_p_rate    = agg.actif ? Math.round(agg.p/agg.actif*10000)/100 : (rows[0]?.abs_p_rate||0);
agg.taux_presence = agg.actif ? Math.round(agg.present/agg.actif*10000)/100 : (rows[0]?.taux_presence||0);
agg.delta         = rows[0]?.delta !== undefined ? parseFloat(rows[0].delta)||0 : Math.round((agg.ist-agg.soll)*100)/100;
agg.maladie       = agg.ml;
agg.mise_en_demeure = agg.md;

const dl = fmtDate(agg.report_date);

function buildMsg(tpls) { return tpls[lang] || tpls.fr; }
let responseText = '';

switch(nlp.intent) {
  case 'get_summary':
    responseText = buildMsg({
      fr: `📊 *Résumé ${scope}*
📅 Date : ${dl}

👥 Actif : ${fmt(agg.actif,0)} | Présents : ${fmt(agg.present,0)}
❌ NP : ${fmt(agg.np,0)} (${fmt(agg.abs_np_rate)}%)
🗓️ P : ${fmt(agg.p,0)} (${fmt(agg.abs_p_rate)}%)
📊 Total Abs : ${fmt(agg.total_abs,0)}
📋 SQ : ${fmt(agg.sq,0)} | AC : ${fmt(agg.ac,0)} | RV : ${fmt(agg.rv,0)}
🏥 Maladie ML : ${fmt(agg.maladie,0)}
⚠️ Mise/dem MD : ${fmt(agg.mise_en_demeure,0)}
✅ Présence : ${fmt(agg.taux_presence)}%
⏱️ H.Sup : ${fmt(agg.heures_sup,0)} | Retard : ${fmt(agg.retard,0)}`,
      ar: `📊 *ملخص ${scope}*
📅 التاريخ: ${dl}

👥 العدد: ${fmt(agg.actif,0)} | الحاضرون: ${fmt(agg.present,0)}
❌ NP: ${fmt(agg.np,0)} (${fmt(agg.abs_np_rate)}%)
🗓️ P: ${fmt(agg.p,0)} (${fmt(agg.abs_p_rate)}%)
📊 إجمالي الغياب: ${fmt(agg.total_abs,0)}
🏥 مرض ML: ${fmt(agg.maladie,0)} | ⚠️ إنذار MD: ${fmt(agg.mise_en_demeure,0)}
✅ نسبة الحضور: ${fmt(agg.taux_presence)}%`,
      tn: `📊 *Résumé ${scope}*
📅 Date: ${dl}

👥 Actifs: ${fmt(agg.actif,0)} | Présents: ${fmt(agg.present,0)}
❌ NP: ${fmt(agg.np,0)} (${fmt(agg.abs_np_rate)}%) | 🗓️ P: ${fmt(agg.p,0)} (${fmt(agg.abs_p_rate)}%)
📊 Total Abs: ${fmt(agg.total_abs,0)}
🏥 ML: ${fmt(agg.maladie,0)} | ⚠️ MD: ${fmt(agg.mise_en_demeure,0)}
✅ Présence: ${fmt(agg.taux_presence)}%`
    });
    break;

  case 'top':
    const topLines = rows.slice(0,5).map((r,i)=>`  ${i+1}. ${r.scope_label||'?'}: ${fmt(r.value||0,0)}`).join('
');
    responseText = buildMsg({
      fr: `🏆 *Top 5 — ${metric.toUpperCase()} — BMW U11*
📅 Date : ${dl}

${topLines}`,
      ar: `🏆 *أعلى 5 — ${metric.toUpperCase()}*
📅 التاريخ: ${dl}

${topLines}`,
      tn: `🏆 *Top 5 — ${metric.toUpperCase()}*
📅 Date: ${dl}

${topLines}`
    });
    break;

  default:
    const templates = {
      np:              { fr:`📊 *Absence NP — ${scope}*
📅 ${dl}

❌ NP = ${fmt(agg.np,0)}
👥 Actif = ${fmt(agg.actif,0)}
📉 Taux NP = ${fmt(agg.abs_np_rate)}%`, ar:`📊 *غياب NP — ${scope}*
📅 ${dl}

❌ NP = ${fmt(agg.np,0)} | نسبة = ${fmt(agg.abs_np_rate)}%`, tn:`📊 *NP — ${scope}*
📅 ${dl}

❌ NP = ${fmt(agg.np,0)} (${fmt(agg.abs_np_rate)}%)` },
      p:               { fr:`📊 *Absence P — ${scope}*
📅 ${dl}

🗓️ P = ${fmt(agg.p,0)}
👥 Actif = ${fmt(agg.actif,0)}
📉 Taux P = ${fmt(agg.abs_p_rate)}%`, ar:`📊 *غياب P — ${scope}*
📅 ${dl}

🗓️ P = ${fmt(agg.p,0)} | نسبة = ${fmt(agg.abs_p_rate)}%`, tn:`📊 *P — ${scope}*
📅 ${dl}

🗓️ P = ${fmt(agg.p,0)} (${fmt(agg.abs_p_rate)}%)` },
      sq:              { fr:`📋 *SQ — ${scope}*
📅 ${dl}

📋 SQ = ${fmt(agg.sq,0)}`, ar:`📋 *SQ — ${scope}*
📅 ${dl}

📋 SQ = ${fmt(agg.sq,0)}`, tn:`📋 *SQ — ${scope}*
📅 ${dl}

SQ = ${fmt(agg.sq,0)}` },
      ac:              { fr:`📋 *AC — ${scope}*
📅 ${dl}

🔁 AC = ${fmt(agg.ac,0)}`, ar:`📋 *AC — ${scope}*
📅 ${dl}

🔁 AC = ${fmt(agg.ac,0)}`, tn:`📋 *AC — ${scope}*
📅 ${dl}

AC = ${fmt(agg.ac,0)}` },
      rv:              { fr:`📋 *RV — ${scope}*
📅 ${dl}

📌 RV = ${fmt(agg.rv,0)}`, ar:`📋 *RV — ${scope}*
📅 ${dl}

📌 RV = ${fmt(agg.rv,0)}`, tn:`📋 *RV — ${scope}*
📅 ${dl}

RV = ${fmt(agg.rv,0)}` },
      maladie:         { fr:`🏥 *Maladie ML — ${scope}*
📅 ${dl}

🤒 ML = ${fmt(agg.maladie,0)}
_(MD = Mise en demeure, indicateur séparé)_`, ar:`🏥 *مرض ML — ${scope}*
📅 ${dl}

🤒 ML = ${fmt(agg.maladie,0)}`, tn:`🏥 *Maladie ML — ${scope}*
📅 ${dl}

🤒 ML = ${fmt(agg.maladie,0)} (ML seulement)` },
      mise_en_demeure: { fr:`⚠️ *Mise en demeure MD — ${scope}*
📅 ${dl}

⚠️ MD = ${fmt(agg.mise_en_demeure,0)}
_(ML = Maladie, indicateur séparé)_`, ar:`⚠️ *إنذار MD — ${scope}*
📅 ${dl}

⚠️ MD = ${fmt(agg.mise_en_demeure,0)}`, tn:`⚠️ *MD — ${scope}*
📅 ${dl}

MD = ${fmt(agg.mise_en_demeure,0)}` },
      abs_np_rate:     { fr:`📊 *Taux NP — ${scope}*
📅 ${dl}

📉 Taux NP = ${fmt(agg.abs_np_rate)}%
   NP = ${fmt(agg.np,0)} / Actif = ${fmt(agg.actif,0)}`, ar:`📊 *نسبة NP — ${scope}*
📅 ${dl}

📉 ${fmt(agg.abs_np_rate)}%`, tn:`📊 *Taux NP — ${scope}*
📅 ${dl}

📉 ${fmt(agg.abs_np_rate)}% — NP=${fmt(agg.np,0)}` },
      abs_p_rate:      { fr:`📊 *Taux P — ${scope}*
📅 ${dl}

📉 Taux P = ${fmt(agg.abs_p_rate)}%
   P = ${fmt(agg.p,0)} / Actif = ${fmt(agg.actif,0)}`, ar:`📊 *نسبة P — ${scope}*
📅 ${dl}

📉 ${fmt(agg.abs_p_rate)}%`, tn:`📊 *Taux P — ${scope}*
📅 ${dl}

📉 ${fmt(agg.abs_p_rate)}%` },
      total_abs:       { fr:`📊 *Total Absences — ${scope}*
📅 ${dl}

